class Solution {
public:
    int findTheLongestSubstring(string s) {
        unordered_map<int, int> stateMap;
        stateMap[0] = -1;
        int mask = 0;
        int maxLen = 0;
        int vowels[26] = {0};
        vowels['a' - 'a'] = 1;
        vowels['e' - 'a'] = 2;
        vowels['i' - 'a'] = 4;
        vowels['o' - 'a'] = 8;
        vowels['u' - 'a'] = 16;

        for (int i = 0; i < s.size(); ++i) {
            if (vowels[s[i] - 'a'] != 0) {
                mask ^= vowels[s[i] - 'a'];
            }
            if (stateMap.count(mask)) {
                maxLen = max(maxLen, i - stateMap[mask]);
            } else {
                stateMap[mask] = i;
            }
        }
        return maxLen;
    }
};

